void VDivFixupF16Vop3::execute_impl(amdgpu::Wavefront &wf) {
  uint32_t sdwa_old_dst_[64] = {};
  if (inst_.src0 == amdgpu::SRC_DPP) {
    uint32_t vb = wf.vgpr_alloc().base;
    uint64_t ex = wf.exec();
    for (uint32_t ln = 0; ln < wf.wf_size(); ++ln)
      if (ex & (1ULL << ln))
        sdwa_old_dst_[ln] = wf.cu().read_vgpr(vb + inst_.vdst, ln);
  }
  if (inst_.src0 == amdgpu::SRC_DPP)
    amdgpu::dpp::apply_dpp(src_operands_[0], dpp_ctrl_, dpp_row_mask_, dpp_bank_mask_,
                           dpp_bound_ctrl_, dpp_src0_, wf);
  if (amdgpu::dpp::is_src_dpp8(inst_.src0))
    amdgpu::dpp::apply_dpp8(src_operands_[0], dpp8_lane_sel_, dpp_src0_, wf);
  if (dpp_src0_)
    src0.set_delegate(dpp_src0_.get());
  if (dpp_src1_)
    src1.set_delegate(dpp_src1_.get());
  uint64_t exec = wf.exec();
  for (uint32_t lane = 0; lane < wf.wf_size(); ++lane) {
    if (!(exec & (1ULL << lane)))
      continue;
    float p = std::bit_cast<float>(src0.read_lane(wf, lane));
    float b = std::bit_cast<float>(src1.read_lane(wf, lane));
    float c = std::bit_cast<float>(src2.read_lane(wf, lane));
    if (inst_.abs & (1u << 0))
      p = std::fabs(p);
    if (inst_.neg & (1u << 0))
      p = -p;
    if (inst_.abs & (1u << 1))
      b = std::fabs(b);
    if (inst_.neg & (1u << 1))
      b = -b;
    if (inst_.abs & (1u << 2))
      c = std::fabs(c);
    if (inst_.neg & (1u << 2))
      c = -c;
    float result;
    if (std::isnan(c))
      result = c;
    else if (std::isnan(b))
      result = b;
    else if (c == 0.0f && b == 0.0f)
      result = std::numeric_limits<float>::quiet_NaN();
    else if (std::isinf(c) && std::isinf(b))
      result = std::numeric_limits<float>::quiet_NaN();
    else if (b == 0.0f) {
      result = std::copysign(
          std::numeric_limits<float>::infinity(),
          std::bit_cast<float>(std::bit_cast<uint32_t>(b) ^ std::bit_cast<uint32_t>(c)));
    } else if (c == 0.0f)
      result = std::copysign(
          0.0f, std::bit_cast<float>(std::bit_cast<uint32_t>(b) ^ std::bit_cast<uint32_t>(c)));
    else if (std::isinf(c)) {
      result = std::copysign(
          std::numeric_limits<float>::infinity(),
          std::bit_cast<float>(std::bit_cast<uint32_t>(b) ^ std::bit_cast<uint32_t>(c)));
    } else if (std::isinf(b))
      result = std::copysign(
          0.0f, std::bit_cast<float>(std::bit_cast<uint32_t>(b) ^ std::bit_cast<uint32_t>(c)));
    else
      result = p;
    if (inst_.omod == 1)
      result *= 2.0f;
    else if (inst_.omod == 2)
      result *= 4.0f;
    else if (inst_.omod == 3)
      result *= 0.5f;
    if (inst_.clamp)
      result = std::clamp(result, 0.0f, 1.0f);
    vdst.write_lane(wf, lane, std::bit_cast<uint32_t>(result));
  }
  if (inst_.src0 == amdgpu::SRC_DPP) {
    uint64_t dpp_write_mask = 0;
    for (uint32_t ln = 0; ln < wf.wf_size(); ++ln) {
      uint32_t row = ln / 16;
      uint32_t bank = (ln % 16) / 4;
      if ((dpp_row_mask_ & (1u << row)) && (dpp_bank_mask_ & (1u << bank)))
        dpp_write_mask |= (1ULL << ln);
    }
    if (dpp_write_mask != ~0ULL) {
      uint64_t ex = wf.exec();
      uint32_t vb = wf.vgpr_alloc().base;
      for (uint32_t ln = 0; ln < wf.wf_size(); ++ln) {
        if ((ex & (1ULL << ln)) && !(dpp_write_mask & (1ULL << ln)))
          wf.cu().write_vgpr(vb + inst_.vdst, ln, sdwa_old_dst_[ln]);
      }
    }
  }
  src0.clear_delegate();
  src1.clear_delegate();
}

